// Login.js
import React, { useState } from 'react';
import './Login.css';

const Login = ({ onLogin }) => {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.email || !formData.password) {
      setError('Email and password are required');
      return;
    }

    setLoading(true);
    setError('');

    // Simple credential validation
    const success = onLogin(formData.email, formData.password);
    
    if (!success) {
      setError('Invalid email or password');
    }
    
    setLoading(false);
  };

  // Pre-fill demo credentials for easy testing
  const fillDemoCredentials = () => {
    setFormData({
      email: 'admin@churnguard.com',
      password: 'admin123'
    });
    setError('');
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <div className="login-logo">
            <h1>🛡️ ChurnGuard</h1>
          </div>
          <h2 className="login-title">
            Administrator Login
          </h2>
          <p className="login-subtitle">
            Sign in to access the Customer Churn Analysis Dashboard
          </p>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <div className="form-group">
            <label htmlFor="email" className="form-label">
              Email Address
            </label>
            <input
              type="email"
              id="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              className="form-input"
              placeholder="Enter your email"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="password" className="form-label">
              Password
            </label>
            <input
              type="password"
              id="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              className="form-input"
              placeholder="Enter your password"
              required
            />
          </div>

          {error && (
            <div className="error-message">
              ⚠️ {error}
            </div>
          )}

          <button 
            type="submit" 
            className="login-button"
            disabled={loading}
          >
            {loading ? (
              <div className="button-loading">
                <div className="spinner"></div>
                Signing In...
              </div>
            ) : (
              'Sign In'
            )}
          </button>

          <button 
            type="button" 
            className="demo-button"
            onClick={fillDemoCredentials}
          >
            Use Demo Credentials
          </button>
        </form>

        <div className="login-footer">
          <div className="demo-credentials">
            <h4>Default Credentials:</h4>
            <p><strong>Email:</strong> admin@churnguard.com</p>
            <p><strong>Password:</strong> admin123</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
